package org.mage.test.cards.single.mat;

import mage.abilities.keyword.HasteAbility;
import mage.constants.PhaseStep;
import mage.constants.Zone;
import org.junit.Test;
import org.mage.test.serverside.base.CardTestPlayerBase;

public class AyaraWidowOfTheRealmTest extends CardTestPlayerBase {

    @Test
    public void returnsArtifactCreatureSacrificedBeforeTransform() {
        addCard(Zone.BATTLEFIELD, playerA, "Ayara, Widow of the Realm");
        addCard(Zone.BATTLEFIELD, playerA, "Noxious Gearhulk");
        addCard(Zone.BATTLEFIELD, playerA, "Swamp", 6);
        addCard(Zone.BATTLEFIELD, playerB, "Plains", 1);

        activateAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{T}, Sacrifice another creature or artifact");
        addTarget(playerA, "Noxious Gearhulk");
        addTarget(playerA, playerB);

        activateAbility(1, PhaseStep.PRECOMBAT_MAIN, playerA, "{5}{R/P}: Transform Ayara");

        addTarget(playerA, "Noxious Gearhulk");
        setChoice(playerA, "No");

        setStrictChooseMode(true);
        setStopAt(1, PhaseStep.POSTCOMBAT_MAIN);
        execute();

        assertPermanentCount(playerA, "Ayara, Furnace Queen", 1);
        assertGraveyardCount(playerA, "Noxious Gearhulk", 0);
        assertPermanentCount(playerA, "Noxious Gearhulk", 1);
        assertAbility(playerA, "Noxious Gearhulk", HasteAbility.getInstance(), true);
    }
}

